//------------------------------------
//	Returns created PLY line body
//------------------------------------
CATBody_var MRFNESCurveBehavior::CreatePLYLine()
{
	CATBody_var outputBody;

	CATIUdfFeatureInstance_var spUDFInst = _spReferenceUDF;
	if (!!spUDFInst)
	{
		CATListValCATBaseUnknown_var* listOfParam = NULL;
		spUDFInst->GetParameters(listOfParam);
	
		if (listOfParam != NULL)
		{
			CATUnicodeString featureName;
		if(_spNESCurveMechFeat != NULL_var)
			featureName = MRFGenericUtils::GetAliasName(_spNESCurveMechFeat);

			CATListOfCATUnicodeString strInputParmList, strParamNameToSetInExcel, paramValueToSetInExcel;
			strInputParmList = GetMatlabParamNameFromNLS(featureName, strParamNameToSetInExcel);

			if (strInputParmList.Size() <= 0 && strInputParmList.Size() < 6)
			{
				//MRFGenericUtils::ShowErrorMessage("Define Parameters of Matlab Input in \" MRFProcessToolNESPackage.Nls \" file Properly ");
				return outputBody;
			}

			CATUnicodeString x1 , y1 , xb , yb , xm , r ;
			int parmFoundCount = 0;

			parmFoundCount = GetMatlabInputValues(strInputParmList, listOfParam, paramValueToSetInExcel);
			if (parmFoundCount == 6)
			{
				GenerateMatlabInputExcel(strParamNameToSetInExcel, paramValueToSetInExcel);
				ReadMatlabGeneratedOutputExcel();
			}
			else
				return NULL_var;
			
		}
	}
	else
	{
		//MRFGenericUtils::ShowErrorMessage("Error in retrieving UDF Instances");
		return outputBody;
	}

	return outputBody;
}
//------------------------------------
//	 Get MATLAB parameter names form NLS file
//------------------------------------
CATListValCATUnicodeString MRFNESCurveBehavior::GetMatlabParamNameFromNLS(CATUnicodeString nlsName, CATListOfCATUnicodeString &listOfnamesToSetInInputExcel)
{
	CATUnicodeString baseNLSFileName = CmdHeader;
	char *folderPathList = NULL;
	baseNLSFileName.Append(".BaseNLS.Name");
	this->_baseNLSFileName = baseNLSFileName = CATMsgCatalog::BuildMessage(CmdHeader, baseNLSFileName.ConvertToChar());

	CATString folderName = baseNLSFileName;

	folderName.Append(".FeatureNLS.FolderName");

	folderName = CATMsgCatalog::BuildMessage(baseNLSFileName.ConvertToChar(), folderName);

	CATUnicodeString strTemp, folderPathNLS;
	bool folderPathFound = false;
	if (CATGetEnvValue("CATMsgCatalogPath", &folderPathList) == CATLibSuccess)
	{
		strTemp = folderPathList;
		cout << "List of Folder Path retrieved from Env Variable is  " << folderPathList << endl;

		CATUnicodeString msg = "The below file does not exists\n";

		stringstream fileStream(strTemp.ConvertToChar());
		while (fileStream.good() && folderPathFound == false)
		{
			string parmName;
			getline(fileStream, parmName, ';');
			folderPathNLS = parmName.c_str();

			int charCountBeforeAddingExtension = 0;

			if (folderPathNLS != "")
			{
				folderPathNLS.Append("\\");
				folderPathNLS.Append(folderName.ConvertToChar());

				cout << "The Feature NLS Path is " << folderPathNLS << endl;
			}

			CATUnicodeString temp = folderPathNLS;
			temp.Append("\\");
			temp.Append(nlsName);
			temp.Append(".CATNls");

			int acessMode = 0;
			if (CATFileAccess(temp.ConvertToChar(), acessMode) == CATLibSuccess)
			{
				_featureNLSPath = folderPathNLS;
				folderPathFound = true;
			}
		}

		
	}
	else
	{
		MRFGenericUtils::ShowErrorMessage("Error In Retieving Catalog Path");

	}


	folderPathNLS.ReplaceAll("\\", "/");

	if(folderPathFound)
		_featureNLSPath = folderPathNLS;


	int index = 0;
	CATMsgCatalog msgCatalog;
	index = msgCatalog.LoadMsgCatalog(nlsName.ConvertToChar(), _featureNLSPath.ConvertToChar());

	if (index == 0)
		cout << "Catalog is Not loaded" << endl;;
	CATListOfCATUnicodeString strInputParmList;
	CATString feature_NLS = nlsName, strConst = "Exe";
	CATUnicodeString strParamCount, exePath, exeName, inputExcelName, outputExcelName;

	CATUnicodeString  parameterNameToSetInInputExcel[100];

	strParamCount = strConst;
	strParamCount.Append(".Parameters.Count");

	strParamCount = (msgCatalog.GetCatalogMsg(strParamCount.ConvertToChar())).BuildMessage();

	//strParamCount = CATMsgCatalog::BuildMessage(feature_NLS, strParamCount.ConvertToChar());
	
	exePath = strConst;
	exePath.Append(".Path");

	_exePath = (msgCatalog.GetCatalogMsg(exePath.ConvertToChar())).BuildMessage();
	
	exeName = strConst;
	exeName.Append(".Name");

	_exeName = (msgCatalog.GetCatalogMsg(exeName.ConvertToChar())).BuildMessage();
	
	inputExcelName = strConst;
	inputExcelName.Append(".InputExcel_Name");

	_inputExcelName = (msgCatalog.GetCatalogMsg(inputExcelName.ConvertToChar())).BuildMessage();
	
	outputExcelName = strConst;
	outputExcelName.Append(".OutputExcel_Name");

	_outputExcelName = (msgCatalog.GetCatalogMsg(outputExcelName.ConvertToChar())).BuildMessage();
	
	int paramCount = 0;
	strParamCount.ConvertToNum(&paramCount);


	for (int i = 1; i <= paramCount; i++)
	{
		CATUnicodeString ID = strConst, rowCount, value;

		rowCount.BuildFromNum(i);

		ID.Append(".Parameters.");
		ID.Append(rowCount);

		value = (msgCatalog.GetCatalogMsg(ID.ConvertToChar())).BuildMessage();

		string inputParm = value.ConvertToChar();
		stringstream  fileStream(inputParm);

		int j = 0;

		while (fileStream.good())
		{
			string parmName;
			getline(fileStream, parmName, ',');
			CATUnicodeString temp = parmName.c_str();

			if (j == 0)
			{
				listOfnamesToSetInInputExcel.Append(temp);
				j++;
			}
			else if (j == 1)
				strInputParmList.Append(temp);	

		}

	}

		return strInputParmList;
}

//------------------------------------
//	Get MATLAB parameter values 
//------------------------------------
int MRFNESCurveBehavior::GetMatlabInputValues(CATListValCATUnicodeString & listOfParmNameFromNLS, CATListValCATBaseUnknown_var* spListOfCkeParm, CATListOfCATUnicodeString &listOfParmValue)
{
	int parmFoundCount = 0;

	for (int i = 1; i <= listOfParmNameFromNLS.Size(); i++)
	{
		CATUnicodeString parmToRetrieve = listOfParmNameFromNLS[i];
		if (spListOfCkeParm)
		{
			for (int j = 1; j <= spListOfCkeParm->Size(); j++)
			{
				CATICkeParm_var spCkeParm = (*spListOfCkeParm)[j];
				if (!!spCkeParm)
				{
					CATUnicodeString parmNameFromUDF = MRFGenericUtils::GetParmNameSplittedFromCATICkeParm(spCkeParm);
					if (parmNameFromUDF.Compare(parmToRetrieve) == 1 || parmNameFromUDF.Compare(parmToRetrieve) == 2)
					{
						parmFoundCount++;
						CATUnicodeString parmValeAsStr = MRFGenericUtils::GetParamValue(spCkeParm);
						listOfParmValue.Append(parmValeAsStr);
						break;
					}
				}
			}

		}
	}

	return parmFoundCount;
}

